var e=[{id:`L2_1`,type:`dialog`,speaker:`BOY_NPC_REVELA_NULL`,text:{KOREA:`50호선 고속도로라고?`,JPN:`50号線の高速道路？`,ENG:`I-50?`,TWN:`50號線高速公路嗎？`},stage:{bg:`VEHICLE`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`BOY_NPC_REVELA_NULL`,text:{KOREA:`그럼 국경을 넘으려던 거야? 그 고속도로는 침식지대가 길을 막아서 지날 수 없을 텐데.`,JPN:`じゃあ国境を越えようとしたの？　あの高速道路は侵食地帯が道を塞いで通れないんじゃない？`,ENG:`Were you trying to cross the national border? That freeway is Corrupted in the middle. You can't go through it.`,TWN:`你是想穿越國界嗎？那個高速公路因為侵蝕地區的關係應該過不去吧？`},stage:{bg:`VEHICLE`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`꼬마, 쓸데없이 끼어들지 말고 운전이나 해.`,JPN:`チビ、余計なこと言わないで運転に集中しろ。`,ENG:`Kid, stop being nosy and keep driving.`,TWN:`喂！你專心開車，插什麼嘴！`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`BOY_NPC_REVELA_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…….`,TWN:`……`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`침식지대야 어찌됐든 네가 원하는 50호선으로 데려다 주겠어.`,JPN:`侵食地帯はおいておくとして、とりあえず50号線に連れていってあげよう。`,ENG:`Corrupted or not, if I-50 is where you want, we'll take you there.`,TWN:`我們會想辦法把你送到那裡的！`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`우리도 이 시간엔 국경지대 근처로 순찰을 돌곤 하니까.`,JPN:`俺たちもこの時間帯は国境地帯の近くをパトロールしたりするからな。`,ENG:`It's about time we patrol around the national border, anyway.`,TWN:`剛好每天這個時間我們也都會去國界周圍巡邏。`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`그러니 걱정 말고, 앉아서 쉬어.`,JPN:`だから心配しないで、そこで休んでな。`,ENG:`So, don't worry and relax.`,TWN:`你放心吧！先好好休息。`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`LUCID_BARCODE_GIRL_NULL`,text:{KOREA:`아…….`,JPN:`ああ……`,ENG:`Oh...`,TWN:`那個……`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_GIRL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`왜. 뭐 문제 있나?`,JPN:`なんだ？　何か問題でもあるのか？`,ENG:`What? Anything wrong?`,TWN:`怎麼了？有什麼問題嗎？`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_GIRL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LUCID_BARCODE_GIRL_NULL`,text:{KOREA:`앗, 아뇨.`,JPN:`あっ、いいえ。`,ENG:`Oh, no.`,TWN:`喔，沒有。`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_GIRL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LUCID_BARCODE_GIRL_NULL`,text:{KOREA:`그게, 이런 호의를 받아보는 건 너무 오랜만이라서요.`,JPN:`実は、こんなご厚意を受けるのは久しぶりで。`,ENG:`It's just... I've never met such kind people for a long time.`,TWN:`只是很久沒有人對我這麼好了。`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_GIRL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LUCID_BARCODE_GIRL_NULL`,text:{KOREA:`저도 참-`,JPN:`私ったら。`,ENG:`I know, it's weird.`,TWN:`好溫暖-`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_GIRL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`아, 저는 루시드라고 해요. 당신은……?`,JPN:`あ、私はルシードです。あなたは……？`,ENG:`Ah, I'm Lucid. You're...?`,TWN:`對了，我叫露西德，請問你怎麼稱呼……？`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`됐어. 잠깐 보고 말 사이니까.`,JPN:`名前なんていいさ。どうせすぐ別れるんだ。`,ENG:`Forget it. It's not like we're going to be friends.`,TWN:`我叫什麼名字不重要，反正我們只僅僅是一面之緣而已。`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`그래도…….`,JPN:`でも……`,ENG:`But still—`,TWN:`可是……`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`꺅!`,JPN:`きゃっ！`,ENG:`Kyaaak!`,TWN:`啊！`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`크윽…….`,JPN:`くっ……`,ENG:`Ugh...`,TWN:`呃……`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`이 빌어먹을 꼬마자식이!`,JPN:`おい、クソガキ！`,ENG:`You stupid kid!`,TWN:`臭小子！`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}}];export{e as default};